namespace :backup do
    desc "Create a Tarball of Database Backup"
    
    task :database, [:name] => [:environment] do |t, args|
        name = "#{args[:name]}.tar.gz" if not args[:name].nil?  # default to current date and time in format YYYYMMDDHHMISS_dbbackup.tar.gz (e.g., '201503261449_mydatabase')
        backuppath = "#{Rails.root}/backups/#{name}"  # default to /backups directory in Rails root folder, e.g.: '/home/user/railsapps/example' or 'C:/Users/UserName/.ruby-app', etc... (e.g., './tmp')
        system "tar -czf '#{backuppath}/#{name}' --absolute-uri=./db"  # run tar command to create a gzipped backup of the database, using current directory as source and saving it in backups folder with given name (.gz format)  
    end    
end